import{api as s}from"./api.DG-MfJ3R.js";const c=document.getElementById("profile-text"),o=document.getElementById("profile-status"),a=document.getElementById("profile-save"),i=document.getElementById("profile-reload"),n=document.getElementById("profile-reset");function t(e,l="text-gray-500"){o.className=`text-xs ${l}`,o.textContent=e}async function r(){t("Загрузка…");try{const e=await s.getProfile();c.value=e.content||"",t("Загружено","text-emerald-400")}catch(e){t("Ошибка загрузки: "+(e instanceof Error?e.message:e),"text-rose-400")}}a.addEventListener("click",async()=>{a.disabled=!0,t("Сохранение…");try{await s.updateProfile(c.value),t("Сохранено ✓","text-emerald-400")}catch(e){t("Ошибка: "+(e instanceof Error?e.message:e),"text-rose-400")}finally{a.disabled=!1}});i.addEventListener("click",r);n.addEventListener("click",async()=>{if(confirm("Сбросить долговременную память агента? Это действие необратимо.")){n.disabled=!0,t("Сброс…");try{await s.resetMemory(),await r(),t("Память сброшена ✓","text-emerald-400")}catch(e){t("Ошибка: "+(e instanceof Error?e.message:e),"text-rose-400")}finally{n.disabled=!1}}});r();
